// src/pages/cleaner/CleanerPortal.jsx
import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import LiveMap from '../../components/LiveMap';

export default function CleanerPortal() {
  const { complaints, updateComplaint } = useApp();
  const [selected, setSelected] = useState(null);

  const activeTasks = complaints.filter(c => c.status !== 'COMPLETED');

  const progressWorkflowState = (task) => {
    const nextStatus = task.status === 'ACCEPTED' ? 'IN_PROGRESS' : 'COMPLETED';
    const clrStatus = nextStatus === 'IN_PROGRESS' ? 'CLEANING' : 'DONE';
    
    const payload = { status: nextStatus, cleanerStatus: clrStatus };
    if (nextStatus === 'COMPLETED') payload.resolutionMins = 25;

    updateComplaint(task.id, payload);
    setSelected(null);
  };

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F7F9FC', overflow: 'hidden', fontFamily: 'sans-serif' }}>
      <Sidebar title="Field Force Ledger" subtitle="Nagpur Ground Operators" navItems={[{ key: 'JOBS', label: 'Assigned Sweeps', icon: '🧹', count: activeTasks.length }]} activeTab="JOBS" onTabChange={() => {}} />

      <div style={{ flex: 1, display: 'flex', padding: 20, gap: 16, overflow: 'hidden' }}>
        <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 10 }}>
          {activeTasks.map(t => (
            <div key={t.id} onClick={() => setSelected(t)} style={{ background: '#fff', padding: 14, borderRadius: 10, border: `1px solid ${selected?.id === t.id ? '#1565C0' : '#DDE3E9'}`, cursor: 'pointer' }}>
              <div style={{ fontWeight: 700 }}>{t.emoji} {t.area} — {t.gtype}</div>
              <div style={{ fontSize: 11, color: '#7A8FA6' }}>Ticket Code Reference: {t.customTicketId}</div>
            </div>
          ))}
        </div>

        <div style={{ flex: 1, background: '#fff', borderRadius: 12, border: '1px solid #DDE3E9', padding: 16, display: 'flex', flexDirection: 'column', gap: 12 }}>
          {selected ? (
            <>
              <h4>Location Telemetry Overlay</h4>
              <LiveMap singlePin={true} singleCoords={{ lat: selected.lat, lng: selected.lng }} height="200px" />
              {selected.image && <img src={selected.image} alt="Evidence Trace Link" style={{ width: '100%', height: 140, objectFit: 'cover', borderRadius: 8 }} />}
              
              <div style={{ marginTop: 'auto' }}>
                {selected.status === 'ACCEPTED' ? (
                  <button onClick={() => progressWorkflowState(selected)} style={{ width: '100%', background: '#4527A0', color: '#fff', padding: 12, border: 'none', borderRadius: 8, fontWeight: 700, cursor: 'pointer' }}>Mark: In-Progress</button>
                ) : (
                  <button onClick={() => progressWorkflowState(selected)} style={{ width: '100%', background: '#2E7D32', color: '#fff', padding: 12, border: 'none', borderRadius: 8, fontWeight: 700, cursor: 'pointer' }}>Mark: Resolved (Done)</button>
                )}
              </div>
            </>
          ) : <div style={{ margin: 'auto', color: '#7A8FA6' }}>Select any ticket allocation data card node to inspect parameters.</div>}
        </div>
      </div>
    </div>
  );
}
